document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("selectedCompany");e&&(e.innerHTML='<span class="header-app-style-company">Εταιρεία :</span>'),setTimeout(()=>{(async()=>{try{const n=document.querySelector('input[name="_csrf"]')?.value||document.querySelector('meta[name="csrf-token"]')?.content,t=await fetch("/api/companyDescription",{method:"GET",headers:{"Content-Type":"application/json",...n&&{"CSRF-Token":n}},credentials:"include"});if(!t.ok)throw new Error(`HTTP ${t.status}: ${t.statusText}`);const o=t.headers.get("content-type");if(!o||!o.includes("application/json")){console.warn("Response is not JSON:",o);const e=await t.text();return void console.log("Raw response:",e)}const s=await t.text();if(!s||""===s.trim())return void console.warn("Empty response from API");let r;try{r=JSON.parse(s)}catch(e){return console.error("JSON parse error:",e),void console.log("Failed to parse:",s)}if(r&&r.newCompanyDescription){const n="Εταιρεία : "+r.newCompanyDescription;if(e){const t=n.length>2?n.substring(0,n.length-1):n;e.innerHTML=t}else console.warn("Element #selectedCompany not found")}}catch(n){console.error("Error updating company description:",n),e&&(e.innerHTML='<span class="header-app-style-company">Εταιρεία :</span>')}})()},100)});